const fs = require('fs');
const path = require('path');

const payloadPath = path.join(
  'G:', 'My Drive', 'optimising-kiwifruit-export',
  '07_reports', 'api_payloads', 'payload_live.json'
);

let payload;
try {
  const raw = fs.readFileSync(payloadPath, 'utf-8');
  payload = JSON.parse(raw);
} catch(e) {
  throw new Error('Failed to read payload_live.json: ' + e.message);
}

const healthScore = payload?.data_quality?.health_score ?? 0;
const season      = payload?.season ?? 'unknown';
const packWeek    = payload?.pack_week ?? 0;
const liveApis    = payload?.live_apis_used ? 'yes' : 'no';
const rainSource  = payload?.rain_source ?? 'etl-only';
const fxEur       = payload?.fx?.nzd_eur ?? null;
const fxJpy       = payload?.fx?.nzd_jpy ?? null;
const corVerified = payload?.corridors_verified ?? null;

return [{
  json: {
    health_score:        healthScore,
    season:              season,
    pack_week:           packWeek,
    live_apis_used:      liveApis,
    rain_source:         rainSource,
    fx_nzd_eur:          fxEur,
    fx_nzd_jpy:          fxJpy,
    corridors_verified:  corVerified,
    payload_path:        payloadPath,
    parsed_at:           new Date().toISOString()
  }
}];

const fs   = require('fs');
const path = require('path');

const baseDir = path.join(
  'G:', 'My Drive', 'optimising-kiwifruit-export',
  '07_reports', 'api_payloads'
);

const payloadPath = path.join(baseDir, 'payload_live.json');
const logPath     = path.join(baseDir, 'etl_log.txt');

// payload_live.json is already in place (written by the python script).
// This node confirms it's valid and appends a success entry to the log.
const ts          = new Date().toISOString();
const hs          = $input.first().json.health_score;
const season      = $input.first().json.season;
const pw          = $input.first().json.pack_week;
const rainSrc     = $input.first().json.rain_source;
const fxEur       = $input.first().json.fx_nzd_eur;
const fxJpy       = $input.first().json.fx_nzd_jpy;
const corV        = $input.first().json.corridors_verified;

const fxStr = fxEur ? `NZD/EUR=${fxEur} NZD/JPY=${fxJpy}` : 'FX=unavailable';
const corStr = corV === true ? 'SH2=verified' : corV === false ? 'SH2=not-found' : 'SH2=unknown';

const logEntry = [
  `[${ts}]`,
  `STATUS=OK`,
  `HEALTH=${hs}`,
  `SEASON=${season}`,
  `PW=${pw}`,
  `RAIN=${rainSrc}`,
  fxStr,
  corStr,
  `PAYLOAD=published`
].join(' | ') + '\n';

fs.appendFileSync(logPath, logEntry, 'utf-8');

return [{ json: { status: 'published', log_entry: logEntry.trim(), payload_path: payloadPath } }];

const fs   = require('fs');
const path = require('path');

const logPath = path.join(
  'G:', 'My Drive', 'optimising-kiwifruit-export',
  '07_reports', 'api_payloads', 'etl_log.txt'
);

const ts  = new Date().toISOString();
const hs  = $input.first().json.health_score;
const ssn = $input.first().json.season;
const pw  = $input.first().json.pack_week;

const logEntry = [
  `[${ts}]`,
  `STATUS=ETL QUALITY ALERT`,
  `HEALTH=${hs}`,
  `SEASON=${ssn}`,
  `PW=${pw}`,
  `THRESHOLD=80`,
  `ACTION=payload NOT published (previous good payload retained)`,
  `REVIEW=Check kiwifruit_export.db data quality and re-run pipeline`
].join(' | ') + '\n';

fs.appendFileSync(logPath, logEntry, 'utf-8');

// Do NOT overwrite payload_live.json — retain last known-good payload
// so the dashboard continues to function with stale-but-valid data.

return [{ json: { status: 'alert', health_score: hs, log_entry: logEntry.trim() } }];
